/// <summary>
/// Provides con demo company reader functionality.
/// </summary>
public class ConDemoCompanyReader
{
}

Method.Source:
/// <summary>
/// Reads the subject of a note from another legal entity.
/// </summary>
/// <param name = "_dataAreaId">The legal entity to read from.</param>
/// <param name = "_noteId">The note identifier.</param>
/// <returns>The subject of the note in the requested legal entity.</returns>
public static Name subjectInCompany(DataAreaId _dataAreaId, Num _noteId)
{
    ConDemoNoteHeader header;

    changeCompany(_dataAreaId)
    {
        select firstonly Subject from header
        where header.NoteId == _noteId;
    }

    return header.Subject;
}

/// <summary>
/// Reads the subject of a note from every supplied legal entity in one query.
/// </summary>
/// <param name = "_companies">A container of legal entity identifiers.</param>
/// <param name = "_noteId">The note identifier.</param>
/// <returns>A container with one formatted entry per legal entity that holds the note.</returns>
public static container subjectsAcrossCompanies(container _companies, Num _noteId)
{
    ConDemoNoteHeader header;
    container result;

    while select crosscompany : _companies DataAreaId, NoteId, Subject from header
    where header.NoteId == _noteId
    {
        result += [strFmt('%1 | %2', header.DataAreaId, header.Subject)];
    }

    return result;
}

/// <summary>
/// Returns the legal entity of the current session.
/// </summary>
/// <returns>The identifier of the current legal entity.</returns>
public static DataAreaId currentCompany()
{
    return curExt();
}
